// ===================================================
// WF-04 Step 1: POST 본문 파싱 + 입력값 검증
// 필수 필드: class_id, member_id, booking_date, participants, amount
// 선택 필드: student_name, student_email, student_phone
// ===================================================

const input = $input.first().json;

// POST 본문 추출 (Content-Type에 따라 body 위치가 다름)
const body = input.body || input;

// === HTML XSS 방지 ===
function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

// === 텍스트 정제 (제어 문자 제거 + 길이 제한) ===
function sanitizeText(str, maxLen) {
  if (!str) return '';
  maxLen = maxLen || 500;
  return String(str)
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
    .trim()
    .substring(0, maxLen);
}

// === 필수 필드 검증 ===
const classId = sanitizeText(body.class_id, 100);
const memberId = sanitizeText(body.member_id, 100);
const bookingDate = sanitizeText(body.booking_date, 30);
const participants = parseInt(body.participants) || 0;
const amount = parseInt(body.amount) || 0;

const missingFields = [];
if (!classId) missingFields.push('class_id');
if (!memberId) missingFields.push('member_id');
if (!bookingDate) missingFields.push('booking_date');
if (participants <= 0) missingFields.push('participants');
if (amount <= 0) missingFields.push('amount');

if (missingFields.length > 0) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'MISSING_PARAMS',
          message: missingFields.join(', ') + ' 파라미터가 필요합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === YYYY-MM-DD 날짜 형식 검증 ===
const dateRegex = /^\d{4}-\d{2}-\d{2}$/;
if (!dateRegex.test(bookingDate)) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_PARAMS',
          message: 'booking_date는 YYYY-MM-DD 형식이어야 합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 금액/인원 범위 검증 ===
if (amount > 10000000) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_PARAMS',
          message: '금액이 유효 범위를 초과합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

if (participants > 50) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_PARAMS',
          message: '인원이 유효 범위를 초과합니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// === 선택 필드 정제 ===
const studentName = sanitizeText(body.student_name, 100);
const studentEmail = sanitizeText(body.student_email, 200);
const studentPhone = sanitizeText(body.student_phone, 20);

// 이메일 형식 간단 검증 (있는 경우만)
if (studentEmail && !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(studentEmail)) {
  return [{
    json: {
      _valid: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INVALID_PARAMS',
          message: 'student_email 형식이 올바르지 않습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _valid: true,
    classId,
    memberId,
    bookingDate,
    participants,
    amount,
    studentName,
    studentEmail,
    studentPhone,
    // XSS-safe 버전 (이메일 HTML용)
    _safe: {
      studentName: escapeHtml(studentName),
      studentEmail: escapeHtml(studentEmail),
      studentPhone: escapeHtml(studentPhone),
      classId: escapeHtml(classId),
      memberId: escapeHtml(memberId)
    }
  }
}];

// ===================================================
// WF-04 Step 2: 클래스 존재 여부 확인 + 파트너 코드 추출
// ===================================================

const response = $input.first().json;
const classesList = response.list || [];

// 검증 데이터를 앞 노드에서 가져옴
const validData = $('Validate Input').first().json;

if (classesList.length === 0) {
  return [{
    json: {
      _classFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'CLASS_NOT_FOUND',
          message: '해당 클래스를 찾을 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const c = classesList[0];

// partner_code 추출 (Links 필드 또는 문자열)
let partnerCode = '';
if (Array.isArray(c.partner_code) && c.partner_code.length > 0) {
  partnerCode = c.partner_code[0].partner_code || c.partner_code[0].Title || '';
} else if (typeof c.partner_code === 'string') {
  partnerCode = c.partner_code;
}

if (!partnerCode) {
  return [{
    json: {
      _classFound: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INTERNAL_ERROR',
          message: '클래스에 파트너 코드가 설정되지 않았습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

return [{
  json: {
    _classFound: true,
    _classData: {
      class_id: c.class_id || '',
      class_name: c.class_name || '',
      category: c.category || '',
      level: c.level || '',
      price: Number(c.price) || 0,
      location: c.location || '',
      duration_min: Number(c.duration_min) || 0,
      makeshop_product_id: c.makeshop_product_id || '',
      partner_code: partnerCode,
      materials_included: c.materials_included || ''
    },
    // 유효성 검증 데이터 전달
    _booking: validData
  }
}];

// ===================================================
// WF-04 Step 3: 수수료 계산 + 자기 결제 방지 + settlement_id 생성
// D+3 정산 방식: 즉시 적립금 지급 X, PENDING_SETTLEMENT 상태로 기록
// ===================================================

// 파트너 정보 확인
const partnerResponse = $input.first().json;
const partnerList = partnerResponse.list || [];

const prevData = $('Check Class Exists').first().json;
const classData = prevData._classData;
const booking = prevData._booking;

if (partnerList.length === 0) {
  return [{
    json: {
      _error: true,
      _isSelfPurchase: false,
      _errorResponse: {
        success: false,
        error: {
          code: 'INTERNAL_ERROR',
          message: '클래스의 파트너 정보를 찾을 수 없습니다.'
        },
        timestamp: new Date().toISOString()
      }
    }
  }];
}

const partner = partnerList[0];

// === 자기 결제 방지 ===
const isSelfPurchase = (booking.memberId === partner.member_id);

// === 수수료 계산 ===
// 개선안 B 적용: GOLD reserveRate = 1.00
const COMMISSION_RATES = {
  SILVER:   { commissionRate: 0.10, reserveRate: 1.00 },
  GOLD:     { commissionRate: 0.12, reserveRate: 1.00 },
  PLATINUM: { commissionRate: 0.15, reserveRate: 0.80 }
};

const grade = (partner.grade || 'SILVER').toUpperCase();
const config = COMMISSION_RATES[grade] || COMMISSION_RATES.SILVER;
const orderAmount = booking.amount;
const commissionAmount = Math.round(orderAmount * config.commissionRate);
const reserveAmount = Math.round(commissionAmount * config.reserveRate);

// === settlement_id 생성: STL_YYYYMMDD_XXXXXX ===
const now = new Date();
const pad = (n) => String(n).padStart(2, '0');
const dateStr = String(now.getFullYear()) + pad(now.getMonth() + 1) + pad(now.getDate());
const randomSuffix = String(Math.floor(100000 + Math.random() * 900000));
const settlementId = 'STL_' + dateStr + '_' + randomSuffix;

// === D+3 정산일 계산 ===
const classDate = new Date(booking.bookingDate + 'T00:00:00+09:00');
const settlementDueDate = new Date(classDate.getTime() + (3 * 24 * 60 * 60 * 1000));
const dueDateStr = settlementDueDate.getFullYear() + '-'
  + pad(settlementDueDate.getMonth() + 1) + '-'
  + pad(settlementDueDate.getDate());

// === 정산 상태 결정 ===
const status = isSelfPurchase ? 'SELF_PURCHASE' : 'PENDING_SETTLEMENT';

// === 개인정보 마스킹 (이메일/텔레그램용) ===
function maskPhone(phone) {
  if (!phone || phone.length < 7) return '***';
  return phone.substring(0, 3) + '-****-' + phone.substring(phone.length - 4);
}

function maskName(name) {
  if (!name || name.length < 2) return '*';
  return name.charAt(0) + '*'.repeat(name.length - 1);
}

function maskEmail(email) {
  if (!email || email.indexOf('@') === -1) return '***';
  const parts = email.split('@');
  const local = parts[0];
  return local.substring(0, Math.min(3, local.length)) + '***@' + parts[1];
}

// === 금액 포맷 ===
function formatCurrency(num) {
  return Number(num).toLocaleString('ko-KR') + '원';
}

// === 날짜 포맷 (한국어) ===
const weekDays = ['일', '월', '화', '수', '목', '금', '토'];
const classDateKR = classDate.getFullYear() + '년 '
  + (classDate.getMonth() + 1) + '월 '
  + classDate.getDate() + '일 ('
  + weekDays[classDate.getDay()] + ')';

return [{
  json: {
    _error: false,
    _isSelfPurchase: isSelfPurchase,
    // 정산 레코드 데이터
    _settlement: {
      settlement_id: settlementId,
      class_id: classData.class_id,
      partner_code: classData.partner_code,
      member_id: booking.memberId,
      order_amount: orderAmount,
      commission_rate: config.commissionRate,
      commission_amount: commissionAmount,
      reserve_rate: config.reserveRate,
      reserve_amount: reserveAmount,
      class_date: booking.bookingDate,
      settlement_due_date: dueDateStr,
      student_count: booking.participants,
      status: status,
      student_name: booking.studentName,
      student_email: booking.studentEmail,
      student_phone: booking.studentPhone,
      created_date: now.toISOString(),
      retry_count: 0
    },
    // 파트너 정보
    _partner: {
      partner_code: partner.partner_code || '',
      partner_name: partner.partner_name || '',
      member_id: partner.member_id || '',
      email: partner.email || '',
      grade: grade,
      location: partner.location || '',
      phone: partner.phone || ''
    },
    // 클래스 정보
    _classData: classData,
    // 예약 원본 데이터
    _booking: booking,
    // 이메일/텔레그램용 가공 데이터
    _display: {
      settlementId,
      className: classData.class_name,
      partnerName: partner.partner_name || '',
      studentName: booking.studentName || '수강생',
      maskedStudentName: maskName(booking.studentName),
      maskedStudentPhone: maskPhone(booking.studentPhone),
      maskedStudentEmail: maskEmail(booking.studentEmail),
      classDateKR,
      classLocation: classData.location || '',
      participants: booking.participants + '명',
      totalAmount: formatCurrency(orderAmount),
      commissionAmount: formatCurrency(commissionAmount),
      reserveAmount: formatCurrency(reserveAmount),
      grade,
      dueDateStr
    }
  }
}];

// 이중 정산 방지: 동일 member_id+class_id+class_date 조합 중복 체크
const result = $input.first().json;
const list = result.list || [];
const calcData = $('Calculate Commission').first().json;

if (list.length > 0) {
  // 이미 존재하는 정산 레코드
  return [{
    json: {
      _isDuplicate: true,
      _existingSettlementId: list[0].settlement_id || list[0].Id || '',
      _display: calcData._display,
      _booking: calcData._booking
    }
  }];
}
return [{
  json: {
    _isDuplicate: false,
    ...calcData
  }
}];

// ===================================================
// WF-04 Step 4: NocoDB 레코드 생성 결과 확인 + 분기 결정
// 자기 결제(SELF_PURCHASE) 여부에 따라 이메일/텔레그램 분기
// ===================================================

const createResult = $input.first().json;
const calcData = $('Calculate Commission').first().json;

// NocoDB 레코드 생성 성공 확인 (Id 필드가 존재하면 성공)
const recordCreated = !!createResult.Id || !!createResult.id;

if (!recordCreated) {
  return [{
    json: {
      _success: false,
      _isSelfPurchase: calcData._isSelfPurchase,
      _errorResponse: {
        success: false,
        error: {
          code: 'RESERVATION_FAILED',
          message: '예약 기록 저장에 실패했습니다.'
        },
        timestamp: new Date().toISOString()
      },
      // 에러 텔레그램 알림용
      _telegramError: '예약 기록 저장 실패: '
        + calcData._display.className + ' / '
        + calcData._display.studentName
    }
  }];
}

// 모든 이전 데이터 전달
return [{
  json: {
    _success: true,
    _isSelfPurchase: calcData._isSelfPurchase,
    _settlement: calcData._settlement,
    _partner: calcData._partner,
    _classData: calcData._classData,
    _booking: calcData._booking,
    _display: calcData._display,
    _nocodbRecordId: createResult.Id || createResult.id
  }
}];

// ===================================================
// WF-04 Step 5a: 수강생 예약 확인 이메일 HTML 생성
// email-templates.md의 이메일 1: 수강생 예약 확인
// XSS 방지: 모든 동적 값 escapeHtml 처리
// ===================================================

const data = $input.first().json;
const d = data._display;
const booking = data._booking;

function escapeHtml(str) {
  if (!str) return '';
  return String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

const sName = escapeHtml(d.studentName);
const cName = escapeHtml(d.className);
const pName = escapeHtml(d.partnerName);
const cDateKR = escapeHtml(d.classDateKR);
const cLocation = escapeHtml(d.classLocation);
const participants = escapeHtml(d.participants);
const totalAmount = escapeHtml(d.totalAmount);
const settlementId = escapeHtml(d.settlementId);
const materialsIncluded = escapeHtml(data._classData.materials_included || '');

// 준비물 블록 (있을 때만)
let preparationsBlock = '';
if (materialsIncluded) {
  preparationsBlock = '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #fef9f0; border-radius: 8px; border-left: 3px solid #b89b5e; margin-bottom: 24px;">'
    + '<tr><td style="padding: 16px 20px;">'
    + '<p style="margin: 0 0 6px; font-size: 13px; font-weight: 700; color: #b89b5e;">준비물 안내</p>'
    + '<p style="margin: 0; font-size: 14px; color: #555555; line-height: 1.6;">' + materialsIncluded + '</p>'
    + '</td></tr></table>';
}

const subject = '[PRESSCO21] ' + d.className + ' 예약이 확정되었습니다';

const html = '<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8" /><meta name="viewport" content="width=device-width, initial-scale=1.0" /><title>PRESSCO21 예약 확인</title></head>'
+ '<body style="margin: 0; padding: 0; background-color: #f8f6f0; font-family: \'Pretendard\', \'Apple SD Gothic Neo\', \'Malgun Gothic\', sans-serif;">'
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #f8f6f0;"><tr><td align="center" style="padding: 24px 16px;">'
+ '<table width="600" cellpadding="0" cellspacing="0" border="0" style="max-width: 600px; width: 100%; background-color: #ffffff; border-radius: 8px; overflow: hidden; box-shadow: 0 2px 8px rgba(0,0,0,0.06);">'
// 헤더
+ '<tr><td style="padding: 24px 32px; text-align: center; border-bottom: 2px solid #b89b5e;">'
+ '<span style="font-size: 22px; font-weight: 700; color: #b89b5e; letter-spacing: 2px;">PRESSCO21</span><br />'
+ '<span style="font-size: 11px; color: #999999; letter-spacing: 1px;">Forever and ever and Blooming</span>'
+ '</td></tr>'
// 본문
+ '<tr><td style="padding: 40px 32px 32px;">'
+ '<p style="margin: 0 0 24px; font-size: 15px; color: #333333; line-height: 1.7;"><strong style="color: #b89b5e;">' + sName + '</strong>님, 안녕하세요!</p>'
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + cName + '</strong> 예약이 확정되었습니다.</p>'
+ '<p style="margin: 0 0 32px; font-size: 15px; color: #333333; line-height: 1.7;"><strong>' + pName + '</strong> 선생님과 함께하는 특별한 시간을 준비하고 있어요.<br />설레는 수업이 될 거예요!</p>'
// 예약 정보 테이블
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="background-color: #faf8f3; border-radius: 8px; border: 1px solid #e8e4db; margin-bottom: 24px;">'
+ '<tr><td style="padding: 20px 24px 12px;"><p style="margin: 0 0 16px; font-size: 14px; font-weight: 700; color: #b89b5e; letter-spacing: 1px;">예약 정보</p></td></tr>'
+ '<tr><td style="padding: 0 24px;"><table width="100%" cellpadding="0" cellspacing="0" border="0">'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; width: 90px; vertical-align: top;">클래스</td><td style="padding: 8px 0; font-size: 14px; color: #333333; font-weight: 600;">' + cName + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">강사</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + pName + ' 선생님</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">일시</td><td style="padding: 8px 0; font-size: 14px; color: #333333; font-weight: 600;">' + cDateKR + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">장소</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + cLocation + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">인원</td><td style="padding: 8px 0; font-size: 14px; color: #333333;">' + participants + '</td></tr>'
+ '<tr><td style="padding: 8px 0; font-size: 13px; color: #999999; vertical-align: top;">결제 금액</td><td style="padding: 8px 0; font-size: 14px; color: #333333; font-weight: 600;">' + totalAmount + '</td></tr>'
+ '</table></td></tr>'
+ '<tr><td style="padding: 12px 24px 16px;"><table width="100%" cellpadding="0" cellspacing="0" border="0" style="border-top: 1px solid #e8e4db;">'
+ '<tr><td style="padding: 12px 0 0; font-size: 12px; color: #999999;">예약번호: ' + settlementId + '</td></tr>'
+ '</table></td></tr></table>'
// 준비물 (조건부)
+ preparationsBlock
// 리마인더 예고
+ '<table width="100%" cellpadding="0" cellspacing="0" border="0" style="margin-bottom: 32px;"><tr><td style="padding: 16px 20px; background-color: #f5f5f5; border-radius: 8px;">'
+ '<p style="margin: 0; font-size: 13px; color: #888888; line-height: 1.6;">수업 3일 전과 하루 전에 리마인더 메일을 보내드릴게요.<br />수업 준비에 참고해주세요.</p>'
+ '</td></tr></table>'
// 마무리
+ '<p style="margin: 0 0 8px; font-size: 15px; color: #333333; line-height: 1.7;">궁금하신 점이 있으시면 언제든 연락주세요.</p>'
+ '<p style="margin: 0; font-size: 15px; color: #333333; line-height: 1.7;">즐거운 시간이 될 거예요!</p>'
+ '</td></tr>'
// 서명
+ '<tr><td style="padding: 0 32px 32px;"><p style="margin: 0; font-size: 14px; color: #b89b5e; font-weight: 600;">PRESSCO21 드림</p></td></tr>'
// 푸터
+ '<tr><td style="padding: 24px 32px; text-align: center; background-color: #faf8f3; border-top: 1px solid #e8e4db;">'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">PRESSCO21 | foreverlove.co.kr</p>'
+ '<p style="margin: 0 0 8px; font-size: 12px; color: #999999;">문의: pressco21@foreverlove.co.kr</p>'
+ '<p style="margin: 0; font-size: 11px; color: #bbbbbb;">이 메일은 PRESSCO21 클래스 예약 관련 안내 메일입니다.</p>'
+ '</td></tr></table></td></tr></table></body></html>';

return [{
  json: {
    ...data,
    _studentEmail: {
      to: booking.studentEmail,
      subject,
      html
    }
  }
}];

// ===================================================
// WF-04 Step 5b: 파트너 예약 알림 이메일 HTML 생성
// email-templates.md의 이메일 6: 파트너 예약 알림
